import React, { useEffect, useState } from "react";
import { Form, Col, Button } from "react-bootstrap";
import { Link, useParams } from "react-router-dom";
import { readDeck } from "../../utils/api/index.js";

function EditDeck() {
    const params = useParams();
    const [deck, setDeck] = useState();

    useEffect(() => {
        async function loadDeck() {
            const deckData = await readDeck(params.deckId);
            setDeck(deckData);
        }
        loadDeck();
    }, [])

    if (!deck) return <p>Loading...</p>
  return (
    <div>
      <Form>
        <Col>
          <h1>Edit Deck</h1>
          <Form.Label className="mt-1">Name</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder={deck.name}
            type="text"
            id="deckTitleInput"
          ></Form.Control>
          <Form.Label className="mt-1">Description</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Brief description of the deck"
            as="textarea"
            id="deckTextInput"
          ></Form.Control>
          <Link to="/">
            <Button className="mt-2 mr-1" variant="secondary">
              Cancel
            </Button>
          </Link>
          <Link to={`/decks/${null}`}>
            <Button className="mt-2 mr-1">
              Submit
            </Button>
          </Link>
        </Col>
      </Form>
    </div>
  );
}

export default EditDeck;
